import { useNavigate } from 'react-router-dom';
import useAuth from '../hooks/useAuth';
import Dashboard from '../components/Dashboard/Dashboard';

export default function DashboardPage() {
  const navigate = useNavigate();
  const { user, logout, isLoggedIn } = useAuth();

  // Simple token check - no useEffect redirect loop
  if (!isLoggedIn()) {
    return (
      <div className="auth-container">
        <div className="auth-form" style={{ textAlign: 'center' }}>
          <h2>Please Login First</h2>
          <p style={{ margin: '15px 0', color: '#666' }}>You need to be logged in to view the dashboard.</p>
          <button className="btn-submit" onClick={() => navigate('/login')}>
            Go to Login
          </button>
        </div>
      </div>
    );
  }

  const handleLogout = () => {
    logout();
    navigate('/login');
  };

  return (
    <div className="dashboard-page">
      <header className="dashboard-header">
        <div className="header-left">
          <h1>Aeronova</h1>
          <span className="header-badge">Supply Chain Platform</span>
        </div>
        <div className="header-right">
          <span className="user-name">Welcome, {user?.name || 'User'}</span>
          <button className="btn-logout" onClick={handleLogout}>Logout</button>
        </div>
      </header>
      <Dashboard />
    </div>
  );
}
